import React, { useRef, useEffect } from 'react'

export default function MediaModal({ item, isVisible, onClose }) {
    const videoRef = useRef(null)

    useEffect(() => {
        if (!isVisible && videoRef.current) {
            videoRef.current.pause()
            videoRef.current.currentTime = 0
        }
    }, [isVisible])

    if (!item) return null

    const isVideo = item.type === 'video'

    return (
        <div
            className={`fixed inset-0 z-50 flex items-center justify-center p-4 sm:p-8 transition-all duration-300 ${isVisible ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
            role="dialog"
            aria-modal="true"
        >
            <div className="absolute inset-0 bg-black/85 backdrop-blur-md" onClick={onClose} />

            <div
                className="relative z-10 w-full max-w-5xl"
                onClick={(e) => e.stopPropagation()}
            >
                <button
                    className="absolute -top-12 right-0 sm:-right-12 sm:top-0 w-10 h-10 rounded-full bg-white/10 hover:bg-white/20 border border-white/20 flex items-center justify-center text-white transition-all duration-200 hover:scale-110"
                    onClick={onClose}
                    aria-label="Close"
                >
                    <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                        <path d="M18 6L6 18M6 6l12 12" />
                    </svg>
                </button>

                <div className="rounded-2xl overflow-hidden shadow-[0_32px_80px_rgba(0,0,0,0.50)] bg-neutral-900">
                    {isVideo ? (
                        <video
                            ref={videoRef}
                            className="w-full max-h-[80vh] object-contain bg-black"
                            src={item.src}
                            poster={item.poster}
                            controls
                            autoPlay
                            playsInline
                        />
                    ) : (
                        <img
                            className="w-full max-h-[82vh] object-contain"
                            src={item.src}
                            alt={item.alt}
                        />
                    )}
                </div>

                <div className="mt-4 flex items-center justify-between px-1">
                    <div>
                        <p className="text-xl text-white font-light tracking-wide">{item.caption}</p>
                        <div className="mt-1 flex items-center gap-2">
                            <div className="w-5 h-px bg-amber-500" />
                            <span className="text-[10px] tracking-[0.16em] uppercase text-white/50">{item.label}</span>
                        </div>
                    </div>
                    <span className="text-[10px] tracking-[0.14em] uppercase text-white/30">
                        {isVideo ? '▶ Film' : '◻ Editorial'}
                    </span>
                </div>
            </div>
        </div>
    )
}
